import { describe, expect, it } from 'vitest';
import { generateGoldenSpiralCity } from '@a0n/aeon-3d/worldsim-city-graph';
import {
  encodeCityGraphRecord,
  packCityKnot,
} from '@a0n/aeon-3d/worldsim-city-knot';
import {
  createThothPlaceSimHost,
  sampleCity,
  simulateWindow,
  recommendPlaces,
  scheduleForDay,
  dayKeyForDate,
} from '../src/thoth-place-sim';

// Winters, CA — a real WORLD_CITY_CATALOG entry (pop 7214) so name and
// lat/lon resolution exercise the production catalog path.
const WINTERS = { name: 'Winters', lat: 38.5249, lon: -121.9708 };
const DAVIS = { name: 'Davis', lat: 38.5449, lon: -121.7405 };

function buildKnot(): Uint8Array {
  const entries = [WINTERS, DAVIS].map((c) => ({
    name: c.name,
    record: encodeCityGraphRecord(
      generateGoldenSpiralCity({ x: 0, y: 0, z: 0 }, 1.2, c.name, {
        sprawl: 1,
        depthCap: 2,
      } as never)
    ),
  }));
  return packCityKnot(entries);
}

/** POIs centred on the city so the Hotelling join lands them on plots. */
function poiElements(c: { lat: number; lon: number }) {
  return [
    {
      type: 'node',
      id: 1,
      lat: c.lat,
      lon: c.lon,
      tags: { name: 'Luna Cafe', amenity: 'cafe' },
    },
    {
      type: 'node',
      id: 2,
      lat: c.lat + 0.001,
      lon: c.lon,
      tags: { name: 'Valley Diner', amenity: 'restaurant' },
    },
    {
      type: 'node',
      id: 3,
      lat: c.lat,
      lon: c.lon + 0.001,
      tags: { name: 'Main St Books', shop: 'books' },
    },
    {
      type: 'node',
      id: 4,
      lat: c.lat - 0.001,
      lon: c.lon,
      tags: { name: 'City Park Pavilion', leisure: 'park' },
    },
    // Unnamed → must be skipped (a sense of place names what it sees).
    { type: 'node', id: 5, lat: c.lat, lon: c.lon, tags: { amenity: 'bench' } },
  ];
}

function makeFetch(knot: Uint8Array, opts: { failKnot?: boolean; failPoi?: boolean } = {}) {
  const calls: string[] = [];
  const fetchImpl = (async (url: string) => {
    calls.push(url);
    if (url.includes('city-graphs.knot')) {
      if (opts.failKnot) return { ok: false, status: 500, arrayBuffer: async () => new ArrayBuffer(0), json: async () => ({}) };
      const buf = knot.buffer.slice(knot.byteOffset, knot.byteOffset + knot.byteLength);
      return { ok: true, status: 200, arrayBuffer: async () => buf, json: async () => ({}) };
    }
    if (url.includes('/api/osm/poi')) {
      if (opts.failPoi) return { ok: false, status: 500, arrayBuffer: async () => new ArrayBuffer(0), json: async () => ({}) };
      // Which city? crude: pick by bbox center latitude.
      const bbox = /bbox=([\d.,-]+)/.exec(url)?.[1]?.split(',').map(Number) ?? [];
      const midLat = ((bbox[0] ?? 0) + (bbox[2] ?? 0)) / 2;
      const city = Math.abs(midLat - WINTERS.lat) < 0.01 ? WINTERS : DAVIS;
      return {
        ok: true,
        status: 200,
        arrayBuffer: async () => new ArrayBuffer(0),
        json: async () => ({ elements: poiElements(city) }),
      };
    }
    return { ok: false, status: 404, arrayBuffer: async () => new ArrayBuffer(0), json: async () => ({}) };
  }) as unknown as typeof fetch;
  return { fetchImpl, calls };
}

describe('thoth-place-sim: loading', () => {
  it('loads a catalog city from the knot by name, with sovereign venues joined', async () => {
    const { fetchImpl } = makeFetch(buildKnot());
    const host = createThothPlaceSimHost({ fetchImpl });
    const sim = await host.loadCitySim({ city: 'Winters' });
    expect(sim).not.toBeNull();
    expect(sim!.cityName).toBe('Winters');
    expect(sim!.source).toBe('catalog-knot');
    expect(sim!.nodes.size).toBeGreaterThan(10);
    expect(sim!.venueCount).toBe(4); // unnamed bench skipped
    expect(sim!.residents.length).toBeGreaterThanOrEqual(20);
    const employed = sim!.residents.filter((r) => r.employed).length;
    expect(employed / sim!.residents.length).toBeGreaterThan(0.4);
    expect(employed / sim!.residents.length).toBeLessThan(0.8);
    expect(sim!.pools.errand.length).toBeGreaterThan(0);
  }, 30000);

  it('resolves by observer lat/lon to the nearest catalog city and caches', async () => {
    const { fetchImpl, calls } = makeFetch(buildKnot());
    const host = createThothPlaceSimHost({ fetchImpl });
    const a = await host.loadCitySim({ lat: 38.52, lon: -121.98 });
    expect(a?.cityName).toBe('Winters');
    const knotCallsAfterFirst = calls.filter((u) => u.includes('knot')).length;
    const b = await host.loadCitySim({ city: 'winters' });
    expect(b).toBe(a); // cache hit — same object
    expect(calls.filter((u) => u.includes('knot')).length).toBe(
      knotCallsAfterFirst
    );
  });

  it('falls back to a synthetic spiral when the knot is unreachable', async () => {
    const { fetchImpl } = makeFetch(buildKnot(), { failKnot: true });
    const host = createThothPlaceSimHost({ fetchImpl });
    const sim = await host.loadCitySim({ city: 'Winters' });
    expect(sim).not.toBeNull();
    expect(sim!.source).toBe('synthetic-spiral');
    expect(sim!.nodes.size).toBeGreaterThan(10);
  });

  it('returns null for an unknown city (honest absence)', async () => {
    const { fetchImpl } = makeFetch(buildKnot());
    const host = createThothPlaceSimHost({ fetchImpl });
    expect(await host.loadCitySim({ city: 'Atlantis-Nowhere' })).toBeNull();
    // Far from any catalog city:
    expect(await host.loadCitySim({ lat: 0.5, lon: 0.5 })).toBeNull();
  });

  it('tolerates a POI outage: sim loads with zero venues', async () => {
    const { fetchImpl } = makeFetch(buildKnot(), { failPoi: true });
    const host = createThothPlaceSimHost({ fetchImpl });
    const sim = await host.loadCitySim({ city: 'Winters' });
    expect(sim).not.toBeNull();
    expect(sim!.venueCount).toBe(0);
    expect(recommendPlaces(sim!, { kind: 'eat', hour: 12 })).toEqual([]);
  });

  it('evicts beyond maxCities (LRU)', async () => {
    const { fetchImpl } = makeFetch(buildKnot());
    const host = createThothPlaceSimHost({ fetchImpl, maxCities: 1 });
    const w = await host.loadCitySim({ city: 'Winters' });
    const d = await host.loadCitySim({ city: 'Davis' });
    expect(w?.cityName).toBe('Winters');
    expect(d?.cityName).toBe('Davis');
    const w2 = await host.loadCitySim({ city: 'Winters' });
    expect(w2).not.toBe(w); // evicted, rebuilt
    expect(w2?.cityName).toBe('Winters');
  });

  it('loads from a local knot file when knotPath is set (zero knot fetches)', async () => {
    const fs = await import('node:fs/promises');
    const os = await import('node:os');
    const path = await import('node:path');
    const file = path.join(await fs.mkdtemp(path.join(os.tmpdir(), 'tps-')), 'city.knot');
    await fs.writeFile(file, buildKnot());
    const { fetchImpl, calls } = makeFetch(buildKnot());
    const host = createThothPlaceSimHost({ fetchImpl, knotPath: file });
    const sim = await host.loadCitySim({ city: 'Winters' });
    expect(sim?.source).toBe('catalog-knot');
    expect(calls.filter((u) => u.includes('knot')).length).toBe(0);
  });
});

describe('thoth-place-sim: sampling + windows', () => {
  async function loadWinters() {
    const { fetchImpl } = makeFetch(buildKnot());
    const host = createThothPlaceSimHost({ fetchImpl });
    const sim = await host.loadCitySim({ city: 'Winters' });
    expect(sim).not.toBeNull();
    return sim!;
  }

  it('sample: deep night is mostly home; midday is mixed', async () => {
    const sim = await loadWinters();
    const night = sampleCity(sim, { hour: 3, dayKey: '2026-06-10' });
    const noon = sampleCity(sim, { hour: 13, dayKey: '2026-06-10' });
    expect((night.activity.home ?? 0) / night.residents).toBeGreaterThan(0.7);
    expect(Object.keys(noon.activity).length).toBeGreaterThanOrEqual(2);
    expect(noon.activity.work ?? 0).toBeGreaterThan(0);
  });

  it('simulateWindow 20→21 (8pm-9pm): person-hours sum ≈ residents × 1h', async () => {
    const sim = await loadWinters();
    const win = simulateWindow(sim, {
      fromHour: 20,
      toHour: 21,
      endIso: '2026-06-10T12:00:00Z',
    });
    const totalHours = Object.values(win.activityPersonHours).reduce(
      (a, b) => a + b,
      0
    );
    expect(totalHours).toBeGreaterThan(sim.residents.length * 0.95);
    expect(totalHours).toBeLessThan(sim.residents.length * 1.05);
    expect(win.perDay).toHaveLength(1);
  });

  it('simulateWindow wraps past midnight (23→1)', async () => {
    const sim = await loadWinters();
    const win = simulateWindow(sim, {
      fromHour: 23,
      toHour: 1,
      endIso: '2026-06-10T12:00:00Z',
    });
    const totalHours = Object.values(win.activityPersonHours).reduce(
      (a, b) => a + b,
      0
    );
    expect(totalHours).toBeGreaterThan(sim.residents.length * 1.9);
    expect(totalHours).toBeLessThan(sim.residents.length * 2.1);
  });

  it('simulateWindow "last week": 7 per-day rows, weekend flags, day texture', async () => {
    const sim = await loadWinters();
    // 2026-06-12 is a Friday → the 7-day window includes Sat 6/6 + Sun 6/7.
    const win = simulateWindow(sim, {
      days: 7,
      endIso: '2026-06-12T12:00:00Z',
    });
    expect(win.perDay).toHaveLength(7);
    expect(win.perDay.filter((d) => d.weekend)).toHaveLength(2);
    // Day-salted schedules: not every day books the same visit count.
    const counts = new Set(win.perDay.map((d) => d.venueVisits));
    expect(counts.size).toBeGreaterThan(1);
    expect(win.venueVisitsTotal).toBe(
      win.perDay.reduce((s, d) => s + d.venueVisits, 0)
    );
  });

  it('weekends send most workers off-shift', async () => {
    const sim = await loadWinters();
    const employed = sim.residents.filter((r) => r.employed);
    expect(employed.length).toBeGreaterThan(5);
    const saturday = '2026-06-06';
    const wednesday = '2026-06-10';
    const offOnSat = employed.filter(
      (r) => !scheduleForDay(r, saturday).employed
    ).length;
    const offOnWed = employed.filter(
      (r) => !scheduleForDay(r, wednesday).employed
    ).length;
    expect(offOnSat / employed.length).toBeGreaterThan(0.5);
    expect(offOnWed).toBe(0);
  });

  it('identity is stable across days: cohort never flips with the day salt', async () => {
    const sim = await loadWinters();
    for (const r of sim.residents.slice(0, 10)) {
      const a = scheduleForDay(r, '2026-06-09');
      const b = scheduleForDay(r, '2026-06-10');
      if (a.employed === b.employed) {
        expect(a.cohort).toBe(b.cohort);
      }
      expect(a.walkSpeed).toBe(b.walkSpeed);
    }
  });
});

describe('thoth-place-sim: recommendations + determinism', () => {
  it('recommend(eat) ranks food venues with honest "why" strings', async () => {
    const { fetchImpl } = makeFetch(buildKnot());
    const host = createThothPlaceSimHost({ fetchImpl });
    const sim = await host.loadCitySim({
      city: 'Winters',
      lat: WINTERS.lat,
      lon: WINTERS.lon,
    });
    const recs = recommendPlaces(sim!, { kind: 'eat', hour: 12.5 });
    expect(recs.length).toBeGreaterThan(0);
    for (const r of recs) {
      expect(r.category).toBe('food');
      expect(r.why).toMatch(/residents headed here|quiet then/);
      expect(typeof r.distanceMeters).toBe('number');
    }
    const coffee = recommendPlaces(sim!, { kind: 'coffee', hour: 9 });
    expect(coffee[0]?.name).toBe('Luna Cafe');
  });

  it('two independent hosts produce byte-identical results (determinism)', async () => {
    const a = createThothPlaceSimHost({ fetchImpl: makeFetch(buildKnot()).fetchImpl });
    const b = createThothPlaceSimHost({ fetchImpl: makeFetch(buildKnot()).fetchImpl });
    const simA = await a.loadCitySim({ city: 'Winters' });
    const simB = await b.loadCitySim({ city: 'Winters' });
    const recA = JSON.stringify(recommendPlaces(simA!, { kind: 'eat', hour: 12 }));
    const recB = JSON.stringify(recommendPlaces(simB!, { kind: 'eat', hour: 12 }));
    expect(recA).toBe(recB);
    const winA = JSON.stringify(
      simulateWindow(simA!, { days: 3, endIso: '2026-06-12T12:00:00Z' })
    );
    const winB = JSON.stringify(
      simulateWindow(simB!, { days: 3, endIso: '2026-06-12T12:00:00Z' })
    );
    expect(winA).toBe(winB);
  });

  it('dayKeyForDate is a stable UTC key', () => {
    expect(dayKeyForDate(new Date('2026-06-12T23:59:00Z'))).toBe('2026-06-12');
  });
});
